using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using verii_metivon_api.Modules.Shipping.Application.Services;namespace verii_metivon_api.Modules.Shipping.Api;[ApiController,Authorize,Route("api/shipments")]public sealed class ShipmentsController(IShipmentService s):ControllerBase{[HttpGet]public async Task<IActionResult>List([FromQuery]ShipmentQuery q,CancellationToken ct){var r=await s.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpPost]public async Task<IActionResult>Create(CreateShipmentRequest x,CancellationToken ct){var r=await s.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/ship")]public async Task<IActionResult>Ship(long id,CancellationToken ct){var r=await s.ShipAsync(id,ct);return StatusCode(r.StatusCode,r);}}
